def gen(rng, size):
    m = rng.randrange(1, min(size, 60) + 1)
    n = rng.randrange(1, min(size, 60) + 1)
    mat = []
    base = rng.randrange(-100, 100)
    for i in range(m):
        row = []
        val = base + i
        for j in range(n):
            val += rng.randrange(1, 4)
            row.append(val)
        mat.append(row)
    # ensure column sortedness by adjusting each cell to dominate the one above
    for i in range(1, m):
        for j in range(n):
            if mat[i][j] <= mat[i - 1][j]:
                mat[i][j] = mat[i - 1][j] + 1
    # re-sort each row to keep row ascending after the column fix
    for i in range(m):
        mat[i].sort()
    for i in range(1, m):
        for j in range(n):
            if mat[i][j] <= mat[i - 1][j]:
                mat[i][j] = mat[i - 1][j] + 1
        mat[i].sort()
    if rng.random() < 0.6:
        target = mat[rng.randrange(m)][rng.randrange(n)]
    else:
        target = rng.randrange(-200, 5000)
    return [mat, target]

